objects.callScript:
function callOperation(row) {                                             var emails = row.contact_email_all;                                   if (typeof emails === 'string') {                                         emails = JSON.parse(emails);                      
    }                               
    if (!Array.isArray(emails) || emails.length === 0) {return [row];}                                  
    var result = [];
    for (var i = 0; i < emails.length; i++) {                             var newRow = {};                                  
        for (var key in row) {
           newRow[key] = row[key];
        }                          
        newRow.contact_email_id = emails[i];                                                       
        result.push(newRow);                              
      }                       
      return result;
  }

objects.projectionScript:
function getAttributesFromCall(resultFromCall)
{
	//return the rows that should be piped to the next operation
	return resultFromCall;
}
